code = """import json

# Get disaster projects from funding database
disaster_projects = var_functions.query_db_90

# Get civic documents
civic_docs = var_functions.query_db_86

# Find 2022 disaster projects
projects_2022 = []

for doc in civic_docs:
    text = doc['text']
    lines = text.split('\n')
    
    for i, line in enumerate(lines):
        line = line.strip()
        
        # Look for 2022 in the line
        if '2022' in line:
            # Check if this is a project name line or nearby
            for lookback in range(max(0, i-2), min(len(lines), i+3)):
                potential_project = lines[lookback].strip()
                
                # Check if line looks like a project name
                if (len(potential_project) > 10 and 
                    potential_project == potential_project.title() and 
                    not potential_project.startswith('(') and 
                    not potential_project.isupper()):
                    
                    # Check if it's a disaster project by looking at context
                    context_start = max(0, lookback-5)
                    context_end = min(len(lines), lookback+10)
                    context = ' '.join(lines[context_start:context_end]).upper()
                    
                    if any(ind in context for ind in ['FEMA', 'CALOES', 'CALJPIA']):
                        # Try to match with funding data
                        proj_clean = potential_project.split('(')[0].strip().upper()
                        
                        for fund_proj in disaster_projects:
                            fund_name = fund_proj['Project_Name'].upper()
                            fund_clean = fund_name.split('(')[0].strip()
                            
                            if proj_clean in fund_clean or fund_clean in proj_clean:
                                project_info = {
                                    'Project_Name': fund_proj['Project_Name'],
                                    'Amount': int(fund_proj['Amount'])
                                }
                                if project_info not in projects_2022:
                                    projects_2022.append(project_info)
                                break

# Also check for explicit 2022 disaster projects in funding names
for proj in disaster_projects:
    if '2022' in proj['Project_Name']:
        project_info = {
            'Project_Name': proj['Project_Name'],
            'Amount': int(proj['Amount'])
        }
        if project_info not in projects_2022:
            projects_2022.append(project_info)

# Calculate totals
total_funding = sum(p['Amount'] for p in projects_2022)
num_projects = len(projects_2022)

result = {
    'total_funding': total_funding,
    'num_projects': num_projects,
    'projects': projects_2022
}

print('__RESULT__:')
print(json.dumps(result, indent=2))"""

